oxy_webhelp_navlinks = {"rbk_backing_up_databases-d30753e32473":{"topics":[{"title":"Database backup customization","shortdesc":"<p class=\"shortdesc\">You can customize the Oracle database backup process to suit your datafile sizes and         rates of change by controlling the number of RMAN channels, multi-section backup settings,         and channel throughput rates.<\/p>","href":"oracle\/database_backup_customization.html","attributes":{"data-id":"database_backup_customization"},"menu":{"hasChildren":false},"tocID":"database_backup_customization-d30753e32484","topics":[]},{"title":"Customizing database backups","shortdesc":"<p class=\"shortdesc\">Define default configuration settings to use during backups of a specific Oracle         database or Oracle RAC.<\/p>","href":"oracle\/customizing_database_backups.html","attributes":{"data-id":"customizing_database_backups"},"menu":{"hasChildren":false},"tocID":"customizing_database_backups-d30753e32495","topics":[]},{"title":"Section sizes for Oracle databases","shortdesc":"<p class=\"shortdesc\">You can expedite Oracle database backups by specifying a section size for the         database, which enables the Rubrik cluster to divide database datafiles into multiple         sections and back them up simultaneously.<\/p>","href":"oracle\/section_sizes_for_oracle_databases.html","attributes":{"data-id":"section_sizes_for_oracle_databases"},"menu":{"hasChildren":false},"tocID":"section_sizes_for_oracle_databases-d30753e32506","topics":[]}]}};